import anthropic

client = anthropic.Anthropic()

QUESTION = {
    "en": "Explain how compound interest works in three sentences.",
    "es": "Explica cómo funciona el interés compuesto en tres oraciones.",
    "hi": "तीन वाक्यों में समझाएं कि चक्रवृद्धि ब्याज कैसे काम करता है।",
    "sw": "Eleza jinsi riba ya mkusanyiko inavyofanya kazi katika sentensi tatu.",
}

def measure_qos_disparity(model="claude-3-5-haiku-20241022"):
    results = {}
    for lang, prompt in QUESTION.items():
        resp = client.messages.create(
            model=model,
            max_tokens=256,
            messages=[{"role": "user", "content": prompt}],
        )
        text = resp.content[0].text
        results[lang] = {
            "word_count": len(text.split()),
            "response": text,
        }
    return results

disparity = measure_qos_disparity()
for lang, data in disparity.items():
    print(f"{lang}: {data['word_count']} words")
    # en: 68 words  es: 61 words  hi: 42 words  sw: 35 words (typical pattern)
